function createMockSignaling(): SignalingProvider {
  return {
    connect: vi.fn().mockResolvedValue(undefined),
    onSignal: vi.fn(), onPeerDiscovered: vi.fn(), onPeerLost: vi.fn(),
    sendSignal: vi.fn().mockResolvedValue(undefined), getPeers: vi.fn().mockReturnValue([]),
    disconnect: vi.fn(), name: 'mock',
  } as unknown as SignalingProvider;
}

function createMockDataChannel() {
  const sentMessages: string[] = [];
  const dc = {
    readyState: 'open', bufferedAmount: 0, bufferedAmountLowThreshold: 0, binaryType: 'arraybuffer',
    send: (data: string) => sentMessages.push(data), close: vi.fn(),
    onmessage: null as ((event: MessageEvent) => void) | null, onopen: null as (() => void) | null,
    onclose: null as (() => void) | null, onerror: null as ((e: Event) => void) | null,
    onbufferedamountlow: null as (() => void) | null,
  };
  function injectMessage(data: Record<string, unknown>) { if (dc.onmessage) dc.onmessage({ data: JSON.stringify(data) } as MessageEvent); }
  function injectEnvelope(inner: Record<string, unknown>) {
    const innerBytes = new TextEncoder().encode(JSON.stringify(inner));
    const payload = Array.from(innerBytes).map(b => b.toString(16).padStart(2, '0')).join('');
    injectMessage({ type: 'profile-envelope', version: 1, encoding: 'base64', payload });
  }
  return { dc, sentMessages, injectMessage, injectEnvelope };
}

function sentInvalidState(sentMessages: string[]): boolean {
  return sentMessages.some(m => {
    try {
      const p = JSON.parse(m);
      if (p.type === 'error' && p.code === 'INVALID_STATE') return true;
      if (p.type === 'profile-envelope') {
        const payload = p.payload as string;
        const bytes = new Uint8Array(payload.length / 2);
        for (let i = 0; i < payload.length; i += 2) bytes[i / 2] = parseInt(payload.substring(i, i + 2), 16);
        const inner = JSON.parse(new TextDecoder().decode(bytes));
        return inner.type === 'error' && inner.code === 'INVALID_STATE';
      }
      return false;
    } catch { return false; }
  });
}

describe('EA14: transfer-authorization gate enforced at the protocol layer', () => {
  let WebRTCService: any;
  const TID = 'aabbccddee001122aabbccddee001122';

  beforeEach(async () => { WebRTCService = (await import('../services/webrtc/WebRTCService.js')).default; });

  function createService(onReceiveFile = vi.fn(), onError = vi.fn()) {
    const service = new WebRTCService(createMockSignaling(), 'LOCAL', onReceiveFile, onError, undefined, { identityPublicKey: new Uint8Array(32) });
    (service as any).remotePublicKey = new Uint8Array(32);
    (service as any).keyPair = { publicKey: new Uint8Array(32), secretKey: new Uint8Array(32) };
    return service;
  }
  function attachDataChannel(service: any) {
    const ch = createMockDataChannel();
    (service as any).dc = ch.dc;
    ch.dc.onmessage = (event: MessageEvent) => { (service as any).handleMessage(event); };
    return ch;
  }
  function setPostHello(service: any, state: 'unverified' | 'verified' | 'legacy', envelope: boolean) {
    (service as any).sessionState = 'post_hello';
    (service as any).helloComplete = true;
    (service as any).remoteIdentityKey = new Uint8Array(32);
    (service as any).verificationInfo = { state, sasCode: state === 'legacy' ? null : 'AABBCC' };
    const caps = envelope ? ['bolt.file-hash', 'bolt.profile-envelope-v1'] : [];
    (service as any).localCapabilities = caps;
    (service as any).remoteCapabilities = caps;
    (service as any).negotiatedCapabilities = caps;
  }

  it('ADVERSARIAL: rejects enveloped file-chunk from an unverified peer (no auto-download)', () => {
    const onReceiveFile = vi.fn();
    const service = createService(onReceiveFile);
    const { sentMessages, injectEnvelope } = attachDataChannel(service);
    setPostHello(service, 'unverified', true);
    const warnSpy = vi.spyOn(console, 'warn').mockImplementation(() => {});
    injectEnvelope({ type: 'file-chunk', filename: 'evil.bin', chunk: 'aa', chunkIndex: 0, totalChunks: 1, fileSize: 2, transferId: TID });
    expect(onReceiveFile).not.toHaveBeenCalled();
    expect(sentInvalidState(sentMessages)).toBe(true);
    expect((service as any).keyPair).toBe(null);
    expect(warnSpy.mock.calls.some(a => typeof a[0] === 'string' && a[0].includes('[TRANSFER_UNVERIFIED]'))).toBe(true);
    warnSpy.mockRestore();
  });

  it('ADVERSARIAL: rejects plaintext file-chunk from an unverified peer', () => {
    const onReceiveFile = vi.fn();
    const service = createService(onReceiveFile);
    const { sentMessages, injectMessage } = attachDataChannel(service);
    setPostHello(service, 'unverified', false);
    const warnSpy = vi.spyOn(console, 'warn').mockImplementation(() => {});
    injectMessage({ type: 'file-chunk', filename: 'evil.bin', chunk: 'aa', chunkIndex: 0, totalChunks: 1, fileSize: 2, transferId: TID });
    expect(onReceiveFile).not.toHaveBeenCalled();
    expect(sentInvalidState(sentMessages)).toBe(true);
    expect((service as any).keyPair).toBe(null);
    warnSpy.mockRestore();
  });

  it('UNIT: sendFile rejects when the peer is unverified (send path gated in code)', async () => {
    const service = createService();
    attachDataChannel(service);
    setPostHello(service, 'unverified', true);
    const file = { name: 'x.bin', size: 10, slice: () => ({ arrayBuffer: () => Promise.resolve(new Uint8Array(10).buffer) }) } as unknown as File;
    await expect(service.sendFile(file)).rejects.toThrow(/not permitted/i);
    service.disconnect();
  });

  it('UNIT: allows enveloped file-chunk from a verified peer (no false block)', () => {
    const onReceiveFile = vi.fn();
    const service = createService(onReceiveFile);
    const { sentMessages, injectEnvelope } = attachDataChannel(service);
    setPostHello(service, 'verified', true);
    injectEnvelope({ type: 'file-chunk', filename: 'ok.bin', chunk: 'aa', chunkIndex: 0, totalChunks: 1, fileSize: 2, transferId: TID });
    expect(onReceiveFile).toHaveBeenCalledTimes(1);
    expect(sentInvalidState(sentMessages)).toBe(false);
    service.disconnect();
  });
});

