changes.proposed:
//! **Exports:**
//! - `sanitize_filename()` — basename extraction + dangerous pattern rejection (TI-02)
//! - `validate_send_file_path()` — absolute path, exists, regular file pre-flight
//! - `parse_transfer_id_bytes()` — hex string → [u8; 16] for BTR transfer context init
//! - `MAX_TRANSFER_SIZE` — 2.5 GB upper bound (TI-03)
//! - `admit_chunk()` — per-chunk receive-buffer bound check (EA7 / DAEMON-RX-BOUND-1)
//! - `MAX_TOTAL_CHUNKS`, `MAX_ACTIVE_RECEIVES` — receive-side resource bounds (EA7)

/// Maximum file size the daemon will accept for a single transfer (2.5 GB).
pub const MAX_TRANSFER_SIZE: u64 = 2_500_000_000;

/// Maximum number of chunks the daemon will accept for a single transfer
/// (EA7 / DAEMON-RX-BOUND-1). Bounds the reassembly loop and the per-transfer
/// chunk map against a malicious `total_chunks`. A full MAX_TRANSFER_SIZE
/// transfer at the 16 KiB profile chunk size (bolt-core DEFAULT_CHUNK_SIZE) is
/// ~152,588 chunks; 200_000 leaves headroom while keeping worst-case chunk-map
/// overhead small.
pub const MAX_TOTAL_CHUNKS: u32 = 200_000;

/// Maximum number of concurrent inbound transfers the daemon will track at once
/// (EA7 / DAEMON-RX-BOUND-1). Bounds `transfer_id` proliferation within a session.
pub const MAX_ACTIVE_RECEIVES: usize = 8;

/// Per-chunk resource-bound check for the inbound file-reassembly loop
/// (EA7 / DAEMON-RX-BOUND-1).
///
/// Every limit is enforced against **actually observed** values — the running
/// `buffered_bytes` sum and the real `chunk_index` / `total_chunks` — never the
/// attacker-declared `file_size`, which the daemon uses only for progress
/// display. Returns the new running buffered-byte total on success, or an error
/// naming the breached bound (the caller aborts the transfer).
///
/// * `chunk_index`    — index of the chunk being admitted
/// * `total_chunks`   — established chunk count for the transfer
/// * `buffered_bytes` — plaintext bytes already retained for this transfer
/// * `chunk_len`      — plaintext length of the chunk being admitted
pub fn admit_chunk(
    chunk_index: u32,
    total_chunks: u32,
    buffered_bytes: u64,
    chunk_len: usize,
) -> Result<u64, String> {
    if total_chunks == 0 || total_chunks > MAX_TOTAL_CHUNKS {
        return Err(format!(
            "total_chunks {total_chunks} outside 1..={MAX_TOTAL_CHUNKS}"
        ));
    }
    if chunk_index >= total_chunks {
        return Err(format!(
            "chunk_index {chunk_index} >= total_chunks {total_chunks}"
        ));
    }
    let new_buffered = buffered_bytes.saturating_add(chunk_len as u64);
    if new_buffered > MAX_TRANSFER_SIZE {
        return Err(format!(
            "buffered {new_buffered} bytes exceeds MAX_TRANSFER_SIZE {MAX_TRANSFER_SIZE}"
        ));
    }
    Ok(new_buffered)
}

