// Adversarial: a tiny declared file_size is irrelevant — it is not even an
// input to admit_chunk (that is the fix). The guard is on ACTUAL buffered
// bytes: one byte past the cap is rejected, huge sums saturate instead of
// panicking, and a stream whose cumulative bytes exceed the cap aborts.
#[test]
fn admit_chunk_rejects_chunk_crossing_cap() {
    assert!(admit_chunk(1, 10, MAX_TRANSFER_SIZE, 1).is_err());
}

