#[test]
fn admit_chunk_aborts_before_buffering_past_cap_despite_tiny_declared_size() {
    // Peer declares a tiny file but streams 100 MB chunks; the running sum,
    // not the declaration, bounds memory.
    let total_chunks = 100u32;
    let chunk_len = 100_000_000usize; // 100 MB per chunk
    let mut buffered = 0u64;
    let mut aborted = false;
    for idx in 0..total_chunks {
        match admit_chunk(idx, total_chunks, buffered, chunk_len) {
            Ok(new_buffered) => {
                assert!(new_buffered <= MAX_TRANSFER_SIZE, "never buffer past cap");
                buffered = new_buffered;
            }
            Err(_) => {
                aborted = true;
                break;
            }
        }
    }
    assert!(aborted, "must abort once cumulative bytes exceed the cap");
    assert!(buffered <= MAX_TRANSFER_SIZE);
}

