    Err(reason) => {
        eprintln!(
            "[TRANSFER] {peer_addr} ABORT transfer {}: {}",
            transfer_id, reason
        );
        active_receives.remove(transfer_id);
        btr_receive_contexts.remove(transfer_id);
        continue;
    }
};

