pub struct RoomManager {
    rooms: DashMap<String, Vec<PeerInfo>>,
    /// Per-resolved-IP active connection counts (EA6). Entries are removed when
    /// they reach zero. Independent of `rooms` (which is keyed on the collapsed
    /// "local" IP) so per-IP limiting is not weakened by the LAN collapse.
    ip_connections: DashMap<String, usize>,
}

/// RAII guard returned by [`RoomManager::try_acquire_ip_slot`]. Releases the
/// per-IP connection slot when dropped (on connection teardown / any early return).
pub struct IpConnGuard {
    manager: Arc<RoomManager>,
    ip: String,
}

impl Drop for IpConnGuard {
    fn drop(&mut self) {
        self.manager.release_ip_slot(&self.ip);
    }
}

