/// Try to reserve a connection slot for `ip` (the resolved client IP, before
/// the private->"local" room collapse). Returns a guard that releases the slot
/// on drop, or `None` if `ip` already holds `max` concurrent connections.
/// Prevents a single host from consuming the global connection pool (EA6).
pub fn try_acquire_ip_slot(self: &Arc<Self>, ip: &str, max: usize) -> Option<IpConnGuard> {
    {
        let mut count = self.ip_connections.entry(ip.to_string()).or_insert(0);
        if *count >= max {
            return None;
        }
        *count += 1;
    }
    Some(IpConnGuard {
        manager: Arc::clone(self),
        ip: ip.to_string(),
    })
}

/// Release one per-IP connection slot for `ip`, removing the entry when it
/// reaches zero. Called by [`IpConnGuard::drop`].
fn release_ip_slot(&self, ip: &str) {
    if let Some(mut count) = self.ip_connections.get_mut(ip) {
        *count = count.saturating_sub(1);
    }
    self.ip_connections.remove_if(ip, |_, v| *v == 0);
}

#[test]
fn per_ip_slot_cap_enforced() {
    use std::sync::Arc;
    let rm = Arc::new(RoomManager::new());
    let mut guards = Vec::new();
    for _ in 0..MAX_CONNECTIONS_PER_IP {
        let g = rm.try_acquire_ip_slot("203.0.113.7", MAX_CONNECTIONS_PER_IP);
        assert!(g.is_some());
        guards.push(g.unwrap());
    }
    // Over cap -> rejected.
    assert!(rm.try_acquire_ip_slot("203.0.113.7", MAX_CONNECTIONS_PER_IP).is_none());
    // A different IP is unaffected.
    assert!(rm.try_acquire_ip_slot("198.51.100.9", MAX_CONNECTIONS_PER_IP).is_some());
    // Releasing one slot frees capacity again.
    guards.pop();
    assert!(rm.try_acquire_ip_slot("203.0.113.7", MAX_CONNECTIONS_PER_IP).is_some());
}

#[test]
fn relay_flood_to_slow_reader_is_bounded() {
    // A peer that never drains its receiver must not accumulate unbounded
    // server-side memory when flooded with relays (EA12).
    let rm = RoomManager::new();
    let (peer, _rx) = make_peer("SLOW", "Slow Reader"); // _rx never drained
    rm.add_peer("10.0.0.1", peer).unwrap();
    let sender = rm.find_peer("10.0.0.1", "SLOW").unwrap();
    let mut accepted = 0usize;
    let mut dropped = 0usize;
    for _ in 0..(RELAY_CHANNEL_CAPACITY * 4) {
        let msg = ServerMessage::Signal { from: "ATTACKER".into(), payload: serde_json::Value::Null };
        match sender.try_send(msg) {
            Ok(()) => accepted += 1,
            Err(_) => dropped += 1,
        }
    }
    assert!(accepted <= RELAY_CHANNEL_CAPACITY, "queue must be bounded");
    assert!(dropped >= RELAY_CHANNEL_CAPACITY * 3, "excess must be dropped");
}

