// Uses tokio-tungstenite + futures-util, both already [dependencies] of the
// crate and thus available to this in-crate #[cfg(test)] module (NO Cargo.toml
// change). Consider #[tokio::test(flavor = "multi_thread", worker_threads = 2)].
#[tokio::test]
async fn interop_register_and_relay() {
    use crate::SignalingServer;
    use futures_util::{SinkExt, StreamExt};
    use tokio_tungstenite::tungstenite::Message;
    // Bind an ephemeral port, then release it for the server to rebind.
    let probe = std::net::TcpListener::bind("127.0.0.1:0").unwrap();
    let port = probe.local_addr().unwrap().port();
    drop(probe);
    let addr: SocketAddr = format!("127.0.0.1:{port}").parse().unwrap();
    tokio::spawn(async move { SignalingServer::new(addr).run().await });
    let url = format!("ws://127.0.0.1:{port}");
    // Retry connect until the server is bound.
    async fn dial(url: &str) -> tokio_tungstenite::WebSocketStream<tokio_tungstenite::MaybeTlsStream<tokio::net::TcpStream>> {
        for _ in 0..50 {
            if let Ok((ws, _)) = tokio_tungstenite::connect_async(url).await { return ws; }
            tokio::time::sleep(std::time::Duration::from_millis(20)).await;
        }
        panic!("server never accepted a connection");
    }
    async fn next_text(ws: &mut tokio_tungstenite::WebSocketStream<tokio_tungstenite::MaybeTlsStream<tokio::net::TcpStream>>) -> Option<String> {
        match tokio::time::timeout(std::time::Duration::from_secs(2), ws.next()).await {
            Ok(Some(Ok(Message::Text(t)))) => Some(t),
            _ => None,
        }
    }
    let mut a = dial(&url).await;
    let mut b = dial(&url).await;
    a.send(Message::Text(r#"{"type":"register","peer_code":"AAAAAA","device_name":"A","device_type":"desktop"}"#.into())).await.unwrap();
    b.send(Message::Text(r#"{"type":"register","peer_code":"BBBBBB","device_name":"B","device_type":"desktop"}"#.into())).await.unwrap();
    assert!(next_text(&mut a).await.unwrap_or_default().contains("\"type\":\"peers\""));
    assert!(next_text(&mut b).await.unwrap_or_default().contains("\"type\":\"peers\""));
    a.send(Message::Text(r#"{"type":"signal","to":"BBBBBB","payload":{"sdp":"x"}}"#.into())).await.unwrap();
    let mut saw = false;
    for _ in 0..5 {
        match next_text(&mut b).await {
            Some(t) if t.contains("\"type\":\"signal\"") && t.contains("\"from\":\"AAAAAA\"") => { saw = true; break; }
            Some(_) => continue,
            None => break,
        }
    }
    assert!(saw, "B must receive the relayed signal from A");
}

