/** IndexedDB-backed pin persistence, keyed by identity public key (base64).
 *  Parity with bolt-daemon trust.rs: legacy peer-code-keyed entries remain but are ignored by lookup. */
export class IndexedDBPinStore implements PinPersistence {
  async getPin(identityKeyB64: string): Promise<PinRecord | null> {
    const db = await openPinDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, 'readonly');
      const store = tx.objectStore(STORE_NAME);
      const req = store.get(identityKeyB64);
      req.onsuccess = () => {
        const val = req.result;
        // Ignore absent and legacy (v1 string / v2 no-peerCode) records — no migration (parity).
        if (!val || typeof val !== 'object' || typeof val.peerCode !== 'string') { resolve(null); return; }
        try {
          resolve({ identityPub: fromBase64(val.identityPub), peerCode: val.peerCode, verified: !!val.verified });
        } catch {
          resolve(null);
        }
      };
      req.onerror = () => reject(req.error);
    });
  }

  async getPinByPeerCode(peerCode: string): Promise<PinRecord | null> {
    const db = await openPinDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, 'readonly');
      const store = tx.objectStore(STORE_NAME);
      const req = store.getAll();
      req.onsuccess = () => {
        const rows = Array.isArray(req.result) ? req.result : [];
        for (const val of rows) {
          if (val && typeof val === 'object' && val.peerCode === peerCode) {
            try {
              resolve({ identityPub: fromBase64(val.identityPub), peerCode: val.peerCode, verified: !!val.verified });
              return;
            } catch { /* skip corrupt row */ }
          }
        }
        resolve(null);
      };
      req.onerror = () => reject(req.error);
    });
  }

  async setPin(identityKeyB64: string, identityPublicKey: Uint8Array, peerCode: string, verified = false): Promise<void> {
    const db = await openPinDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, 'readwrite');
      const store = tx.objectStore(STORE_NAME);
      store.put({ identityPub: toBase64(identityPublicKey), peerCode, verified }, identityKeyB64);
      tx.oncomplete = () => resolve();
      tx.onerror = () => reject(tx.error);
    });
  }

  async removePin(identityKeyB64: string): Promise<void> {
    const db = await openPinDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE_NAME, 'readwrite');
      const store = tx.objectStore(STORE_NAME);
      store.delete(identityKeyB64);
      tx.oncomplete = () => resolve();
      tx.onerror = () => reject(tx.error);
    });
  }

  async markVerified(identityKeyB64: string): Promise<void> {
    const existing = await this.getPin(identityKeyB64);
    if (!existing) return;
    await this.setPin(identityKeyB64, existing.identityPub, existing.peerCode, true);
  }
}

