/**
 * Verify a peer's identity against the pin store.
 *
 * - If no pin exists: pin the identity (first contact / TOFU), verified=false
 * - If pin matches: return with current verified status
 * - If pin mismatches: throw KeyMismatchError (fail-closed)
 */
export async function verifyPinnedIdentity(
  pinStore: PinPersistence,
  peerCode: string,
  identityPublicKey: Uint8Array,
): Promise<PinVerifyResult> {
  const existing = await pinStore.getPin(peerCode);

  if (!existing) {
    await pinStore.setPin(peerCode, identityPublicKey, false);
    return { outcome: 'pinned' };
  }

  if (uint8Equal(existing.identityPub, identityPublicKey)) {
    return { outcome: 'verified', verified: existing.verified };
  }

  throw new KeyMismatchError(peerCode, existing.identityPub, identityPublicKey);
}

changes.proposed:
/**
 * Verify a peer's identity against the pin store (TOFU). Pinning is keyed by the
 * remote identity public key (PROTOCOL.md §2); peerCode is a non-authoritative label.
 *
 * - Known identity key: recognized across peer-code rotation -> return verified status.
 * - Unknown identity key, but the peerCode label was previously bound to a different
 *   identity: throw KeyMismatchError (fail-closed, PROTOCOL.md §2 key-mismatch).
 * - Otherwise first contact: pin the identity (verified=false) and return 'pinned'.
 */
export async function verifyPinnedIdentity(
  pinStore: PinPersistence,
  peerCode: string,
  identityPublicKey: Uint8Array,
): Promise<PinVerifyResult> {
  const identityKeyB64 = toBase64(identityPublicKey);

  const existing = await pinStore.getPin(identityKeyB64);
  if (existing) {
    return { outcome: 'verified', verified: existing.verified };
  }

  const byLabel = await pinStore.getPinByPeerCode(peerCode);
  if (byLabel && !uint8Equal(byLabel.identityPub, identityPublicKey)) {
    throw new KeyMismatchError(peerCode, byLabel.identityPub, identityPublicKey);
  }

  await pinStore.setPin(identityKeyB64, identityPublicKey, peerCode, false);
  return { outcome: 'pinned' };
}

