import { describe, it, expect } from 'vitest';
import { KeyMismatchError, toBase64 } from '@the9ines/bolt-core';
import { MemoryPinStore, verifyPinnedIdentity } from '../services/identity/pin-store.js';

function randomKey(): Uint8Array {
  const key = new Uint8Array(32);
  crypto.getRandomValues(key);
  return key;
}

describe('MemoryPinStore (identity-keyed, EA5)', () => {
  it('returns null for an unknown identity', async () => {
    const store = new MemoryPinStore();
    expect(await store.getPin(toBase64(randomKey()))).toBeNull();
  });

  it('stores/retrieves by identity key with peer code as metadata', async () => {
    const store = new MemoryPinStore();
    const key = randomKey();
    await store.setPin(toBase64(key), key, 'PEER01');
    const pin = await store.getPin(toBase64(key));
    expect(pin!.identityPub).toEqual(key);
    expect(pin!.peerCode).toBe('PEER01');
    expect(pin!.verified).toBe(false);
    expect((await store.getPinByPeerCode('PEER01'))!.identityPub).toEqual(key);
  });

  it('does NOT collide distinct identities that share a constant peer code (WS/WT case)', async () => {
    const store = new MemoryPinStore();
    const k1 = randomKey();
    const k2 = randomKey();
    await store.setPin(toBase64(k1), k1, 'ws-daemon');
    await store.setPin(toBase64(k2), k2, 'ws-daemon');
    expect((await store.getPin(toBase64(k1)))!.identityPub).toEqual(k1);
    expect((await store.getPin(toBase64(k2)))!.identityPub).toEqual(k2);
  });

  it('markVerified flips verified by identity key', async () => {
    const store = new MemoryPinStore();
    const key = randomKey();
    await store.setPin(toBase64(key), key, 'PEER01');
    await store.markVerified(toBase64(key));
    expect((await store.getPin(toBase64(key)))!.verified).toBe(true);
  });
});

describe('verifyPinnedIdentity — identity-keyed TOFU (EA5)', () => {
  it('pins on first contact', async () => {
    const store = new MemoryPinStore();
    const key = randomKey();
    expect(await verifyPinnedIdentity(store, 'NEWPEER', key)).toEqual({ outcome: 'pinned' });
    const pin = await store.getPin(toBase64(key));
    expect(pin!.peerCode).toBe('NEWPEER');
    expect(pin!.verified).toBe(false);
  });

  it('recognizes the same identity under a ROTATED peer code (continuity — the EA5 fix)', async () => {
    const store = new MemoryPinStore();
    const id = randomKey();
    expect(await verifyPinnedIdentity(store, 'P1', id)).toEqual({ outcome: 'pinned' });
    expect(await verifyPinnedIdentity(store, 'P2', id)).toEqual({ outcome: 'verified', verified: false });
  });

  it('returns verified after markVerified', async () => {
    const store = new MemoryPinStore();
    const key = randomKey();
    await verifyPinnedIdentity(store, 'PEER01', key);
    await store.markVerified(toBase64(key));
    expect(await verifyPinnedIdentity(store, 'PEER01', key)).toEqual({ outcome: 'verified', verified: true });
  });

  // ADVERSARIAL 1: changed identity key on a known peer -> KEY_MISMATCH
  it('throws KEY_MISMATCH when a known peer-code label presents a changed identity key', async () => {
    const store = new MemoryPinStore();
    const pinned = randomKey();
    const rotated = randomKey();
    await verifyPinnedIdentity(store, 'PEER01', pinned);
    await expect(verifyPinnedIdentity(store, 'PEER01', rotated)).rejects.toThrow(KeyMismatchError);
    try {
      await verifyPinnedIdentity(store, 'PEER01', rotated);
      expect.fail('should have thrown');
    } catch (err) {
      const e = err as KeyMismatchError;
      expect(e.peerCode).toBe('PEER01');
      expect(e.expected).toEqual(pinned);
      expect(e.received).toEqual(rotated);
    }
  });

  // ADVERSARIAL 2: a reused peer code with a new identity key -> not silently trusted
  it('does not silently trust a reused peer code carrying a new identity key', async () => {
    const store = new MemoryPinStore();
    const trusted = randomKey();
    const attacker = randomKey();
    await verifyPinnedIdentity(store, 'DUP', trusted);
    await store.markVerified(toBase64(trusted));
    await expect(verifyPinnedIdentity(store, 'DUP', attacker)).rejects.toThrow(KeyMismatchError);
    expect(await store.getPin(toBase64(attacker))).toBeNull();
  });
});

import { WsDataTransport } from '../services/ws-transport/WsDataTransport.js';
import { BrowserAppTransport } from '../services/ws-transport/BrowserAppTransport.js';
import { MemoryPinStore } from '../services/identity/pin-store.js';

async function driveWsHello(
  pinStore: MemoryPinStore,
  daemonIdentity: { publicKey: Uint8Array },
) {
  const clientId = generateIdentityKeyPair();
  const transport = new WsDataTransport({
    daemonUrl: 'ws://daemon',
    identityPublicKey: clientId.publicKey,
    pinStore,
    onError: () => {},
  });
  const connectP = transport.connect();
  const ws = getLastMockWs();
  ws.simulateOpen();
  const clientPk = fromBase64(JSON.parse(ws.sentMessages[0]).publicKey);
  const daemonEph = generateEphemeralKeyPair();
  ws.simulateMessage(JSON.stringify({ type: 'session-key', publicKey: toBase64(daemonEph.publicKey) }));
  ws.simulateMessage(buildHelloResponse(daemonEph, clientPk, daemonIdentity));
  await new Promise((r) => setTimeout(r, 0)); // flush async processHello
  return { transport, ws, connectP };
}

describe('WS TOFU threading (EA13) + identity-keyed pinning (EA5)', () => {
  beforeEach(() => installMockWebSocket());
  afterEach(() => uninstallMockWebSocket());

  it('threads the pin store: first contact pins the daemon identity; reconnect is recognized', async () => {
    const pinStore = new MemoryPinStore();
    const daemonId = generateIdentityKeyPair();
    const s1 = await driveWsHello(pinStore, daemonId);
    expect(await s1.connectP).toBe(true);
    expect(await pinStore.getPin(toBase64(daemonId.publicKey))).not.toBeNull();
    s1.transport.disconnect();
    const s2 = await driveWsHello(pinStore, daemonId);
    expect(await s2.connectP).toBe(true);
    const anyError = s2.ws.sentMessages.map((m) => JSON.parse(m)).some((m) => m.type === 'error');
    expect(anyError).toBe(false);
    s2.transport.disconnect();
  });

  it('fails closed with KEY_MISMATCH when the daemon presents a changed identity', async () => {
    const pinStore = new MemoryPinStore();
    const daemonA = generateIdentityKeyPair();
    const daemonB = generateIdentityKeyPair();
    const s1 = await driveWsHello(pinStore, daemonA);
    expect(await s1.connectP).toBe(true);
    s1.transport.disconnect();
    const s2 = await driveWsHello(pinStore, daemonB);
    const errFrame = s2.ws.sentMessages.map((m) => JSON.parse(m)).find((m) => m.type === 'error');
    expect(errFrame?.code).toBe('KEY_MISMATCH');
    expect(s2.transport.connected).toBe(false);
  });
});

