  async setPin(id: string, pub: Uint8Array, peerCode: string, v = false) { this.pins.set(id, { identityPub: pub, peerCode, verified: v }); }
  async removePin(id: string) { this.pins.delete(id); }
  async markVerified(id: string) { const p = this.pins.get(id); if (p) p.verified = true; }
},
